const results = $input.all().map(i => i.json);

// Group by category for easier reading
const grouped = {};
for (const row of results) {
  const cat = row.category || 'other';
  if (!grouped[cat]) grouped[cat] = {};
  grouped[cat][row.data_type] = {
    values: row.available_values || [],
    count: row.total_count || 0
  };
}

// Build a human-readable summary
let summary = '## DATABASE DISCOVERY RESULTS\n\n';

for (const [category, types] of Object.entries(grouped)) {
  summary += `### ${category.toUpperCase().replace('_', ' ')}\n`;
  for (const [dataType, data] of Object.entries(types)) {
    if (data.values && data.values.length > 0) {
      const displayValues = data.values.slice(0, 20);
      const hasMore = data.values.length > 20;
      summary += `- **${dataType}** (${data.count} total): ${displayValues.join(', ')}${hasMore ? '...' : ''}\n`;
    } else if (data.count > 0) {
      summary += `- **${dataType}**: ${data.count}\n`;
    }
  }
  summary += '\n';
}

return [{
  json: {
    success: true,
    tool: 'discover_database',
    message: 'Database discovery complete. Use these values to inform your searches.',
    summary: summary,
    raw_data: grouped
  }
}];
